import type { Metadata } from "next";
import YearEndDeclaration from "./YearEndDeclaration";

export const metadata: Metadata = {
  title: "年末調整 申告 | ぐんじょう給与",
  description:
    "従業員が2026年分の年末調整を申告する画面。扶養親族・配偶者控除の判定、生命保険料／地震保険料控除の自動計算（上限あり）、基礎控除・住宅借入金等特別控除・小規模企業共済等掛金の入力、課税対象額〜年調年税額〜過不足額（還付／追徴）の自動精算、申告者→人事確認の提出フローと差戻しに対応します。",
};

export default function YearEndPage() {
  return <YearEndDeclaration />;
}

/**
 * 年末調整 計算ロジック (cold-built for the @gunjo/ui consumer test).
 *
 * NOTE — the library ships NO tax helpers (caps, 控除判定, 累進税額, 過不足精算),
 * which is correct for a general design system, but means all of this is consumer
 * code. Kept pure + unit-testable, separate from the React layer.
 *
 * Figures follow the 令和(2020+) 年末調整 framework, simplified for one employee:
 * - 生命保険料控除: 新制度 only (一般 / 介護医療 / 個人年金 各上限4万・合計上限12万)
 * - 地震保険料控除: 上限5万
 * - 基礎控除: 合計所得2,400万以下=48万 (以降は逓減)
 * - 配偶者(特別)控除: 本人所得900万以下を前提に配偶者の所得で判定
 * - 所得税: 超過累進 → 復興特別所得税 ×1.021
 */

export type InsuranceKind = "general-life" | "care-medical" | "pension" | "earthquake"

export interface InsuranceRow {
  id: string
  company: string
  kind: InsuranceKind | ""
  amount?: number
}

export type DependentCategory = "general" | "specific" | "elderly" | "cohabiting-elderly"

export interface DependentRow {
  id: string
  name: string
  relationship: string
  birthDate: string // ISO yyyy-MM-dd
  category: DependentCategory | ""
  estimatedIncome?: number
}

/** 一つの生命保険カテゴリ（新制度）の控除額. 各カテゴリ上限 40,000円. */
export function lifeInsuranceCategoryDeduction(premium: number): number {
  if (premium <= 0) return 0
  if (premium <= 20000) return premium
  if (premium <= 40000) return Math.floor(premium / 2) + 10000
  if (premium <= 80000) return Math.floor(premium / 4) + 20000
  return 40000
}

/** 地震保険料控除. 上限 50,000円. */
export function earthquakeDeduction(premium: number): number {
  if (premium <= 0) return 0
  return Math.min(premium, 50000)
}

export interface InsuranceDeductionBreakdown {
  generalLife: number
  careMedical: number
  pension: number
  /** 生命保険料控除の合計（3区分合算・上限12万）. */
  lifeTotal: number
  earthquake: number
  /** 保険料控除 総額. */
  total: number
}

export function computeInsuranceDeduction(rows: InsuranceRow[]): InsuranceDeductionBreakdown {
  const sum = (kind: InsuranceKind) =>
    rows.filter((r) => r.kind === kind).reduce((acc, r) => acc + (r.amount ?? 0), 0)

  const generalLife = lifeInsuranceCategoryDeduction(sum("general-life"))
  const careMedical = lifeInsuranceCategoryDeduction(sum("care-medical"))
  const pension = lifeInsuranceCategoryDeduction(sum("pension"))
  // 3区分の合算は 120,000円 が上限.
  const lifeTotal = Math.min(generalLife + careMedical + pension, 120000)
  const earthquake = earthquakeDeduction(sum("earthquake"))

  return {
    generalLife,
    careMedical,
    pension,
    lifeTotal,
    earthquake,
    total: lifeTotal + earthquake,
  }
}

/** 基礎控除. 本人の合計所得金額に応じて逓減. */
export function basicDeduction(totalIncome: number): number {
  if (totalIncome <= 24_000_000) return 480_000
  if (totalIncome <= 24_500_000) return 320_000
  if (totalIncome <= 25_000_000) return 160_000
  return 0
}

export type SpouseDeductionResult = {
  /** 控除額. */
  amount: number
  /** 判定区分の表示名. */
  kind: "配偶者控除" | "配偶者特別控除" | "対象外"
}

/**
 * 配偶者(特別)控除の判定. 本人の合計所得 900万円以下を前提に簡略化.
 * @param hasSpouse 配偶者の有無
 * @param spouseIncome 配偶者の合計所得見積額（給与なら給与所得）
 */
export function spouseDeduction(hasSpouse: boolean, spouseIncome: number): SpouseDeductionResult {
  if (!hasSpouse) return { amount: 0, kind: "対象外" }
  // 配偶者控除: 配偶者の合計所得 48万円以下.
  if (spouseIncome <= 480_000) return { amount: 380_000, kind: "配偶者控除" }
  // 配偶者特別控除: 48万超〜133万円. 逓減（本人所得900万以下の区分）.
  if (spouseIncome <= 950_000) return { amount: 380_000, kind: "配偶者特別控除" }
  if (spouseIncome <= 1_000_000) return { amount: 360_000, kind: "配偶者特別控除" }
  if (spouseIncome <= 1_050_000) return { amount: 310_000, kind: "配偶者特別控除" }
  if (spouseIncome <= 1_100_000) return { amount: 260_000, kind: "配偶者特別控除" }
  if (spouseIncome <= 1_150_000) return { amount: 210_000, kind: "配偶者特別控除" }
  if (spouseIncome <= 1_200_000) return { amount: 160_000, kind: "配偶者特別控除" }
  if (spouseIncome <= 1_250_000) return { amount: 110_000, kind: "配偶者特別控除" }
  if (spouseIncome <= 1_300_000) return { amount: 60_000, kind: "配偶者特別控除" }
  if (spouseIncome <= 1_330_000) return { amount: 30_000, kind: "配偶者特別控除" }
  return { amount: 0, kind: "対象外" }
}

/** 扶養控除. 区分 × 所得見積額48万円以下 を満たす行のみ合算. */
export function dependentDeduction(rows: DependentRow[]): number {
  const PER_CATEGORY: Record<DependentCategory, number> = {
    general: 380_000, // 一般扶養
    specific: 630_000, // 特定扶養 (19〜22歳)
    elderly: 480_000, // 老人扶養
    "cohabiting-elderly": 580_000, // 同居老親
  }
  return rows.reduce((acc, r) => {
    if (!r.category) return acc
    if ((r.estimatedIncome ?? 0) > 480_000) return acc // 扶養の所得要件
    return acc + PER_CATEGORY[r.category]
  }, 0)
}

/** 所得税の超過累進（復興特別所得税 前）. 課税所得(千円未満切捨て)に適用. */
export function incomeTaxBeforeSurtax(taxableIncome: number): number {
  const base = Math.floor(taxableIncome / 1000) * 1000
  const brackets: Array<{ upTo: number; rate: number; deduct: number }> = [
    { upTo: 1_950_000, rate: 0.05, deduct: 0 },
    { upTo: 3_300_000, rate: 0.1, deduct: 97_500 },
    { upTo: 6_950_000, rate: 0.2, deduct: 427_500 },
    { upTo: 9_000_000, rate: 0.23, deduct: 636_000 },
    { upTo: 18_000_000, rate: 0.33, deduct: 1_536_000 },
    { upTo: 40_000_000, rate: 0.4, deduct: 2_796_000 },
    { upTo: Infinity, rate: 0.45, deduct: 4_796_000 },
  ]
  const b = brackets.find((x) => base <= x.upTo)!
  return Math.max(0, Math.floor(base * b.rate - b.deduct))
}

export interface ReconciliationInput {
  /** 給与所得控除後の金額. */
  incomeAfterEmploymentDeduction: number
  /** 社会保険料（給与天引分）. */
  socialInsurance: number
  insuranceDeduction: number
  basicDeduction: number
  spouseDeduction: number
  dependentDeduction: number
  /** 住宅借入金等特別控除（税額控除）. */
  housingLoanCredit: number
  /** 小規模企業共済等掛金（所得控除）. */
  smallEnterpriseMutualAid: number
  /** 既に源泉徴収済みの税額（年間累計）. */
  taxAlreadyWithheld: number
}

export interface ReconciliationResult {
  /** 所得控除の合計. */
  totalIncomeDeductions: number
  /** 課税対象額（千円未満切捨て）. */
  taxableIncome: number
  /** 算出税額（復興特別前・住宅ローン控除前）. */
  calculatedTax: number
  /** 住宅ローン控除適用後. */
  taxAfterHousingCredit: number
  /** 年調年税額（復興特別所得税込み・百円未満切捨て）. */
  finalAnnualTax: number
  /** 過不足額 = 年調年税額 − 既源泉徴収税額. 正なら追徴・負なら還付. */
  settlement: number
  /** "refund"=還付 / "collect"=追徴 / "zero"=過不足なし. */
  settlementType: "refund" | "collect" | "zero"
}

export function reconcile(input: ReconciliationInput): ReconciliationResult {
  const totalIncomeDeductions =
    input.socialInsurance +
    input.insuranceDeduction +
    input.basicDeduction +
    input.spouseDeduction +
    input.dependentDeduction +
    input.smallEnterpriseMutualAid

  const taxableRaw = Math.max(0, input.incomeAfterEmploymentDeduction - totalIncomeDeductions)
  const taxableIncome = Math.floor(taxableRaw / 1000) * 1000

  const calculatedTax = incomeTaxBeforeSurtax(taxableIncome)
  const taxAfterHousingCredit = Math.max(0, calculatedTax - input.housingLoanCredit)
  // 復興特別所得税 2.1%, 年調年税額は百円未満切捨て.
  const finalAnnualTax = Math.floor((taxAfterHousingCredit * 1.021) / 100) * 100

  const settlement = finalAnnualTax - input.taxAlreadyWithheld
  const settlementType = settlement > 0 ? "collect" : settlement < 0 ? "refund" : "zero"

  return {
    totalIncomeDeductions,
    taxableIncome,
    calculatedTax,
    taxAfterHousingCredit,
    finalAnnualTax,
    settlement,
    settlementType,
  }
}

"use client";

import * as React from "react";
import { ja } from "date-fns/locale/ja";
import {
  IconCheck,
  IconClipboardCheck,
  IconArrowBackUp,
  IconCoin,
  IconAlertTriangle,
  IconInfoCircle,
} from "@tabler/icons-react";

import {
  ThemeProvider,
  Container,
  VStack,
  HStack,
  Cluster,
  Grid,
  Separator,
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  Badge,
  Alert,
  AlertTitle,
  AlertDescription,
  Button,
  Input,
  Select,
  CurrencyInput,
  DatePicker,
  RadioGroup,
  RadioGroupItem,
  Switch,
  Textarea,
  Statistic,
  EditableDataTable,
  ApprovalSteps,
  Form,
  FormField,
  FormLabel,
  FormControl,
  FormDescription,
  FormMessage,
  formatCurrency,
  type EditableColumn,
  type ApprovalStep,
} from "@gunjo/ui";

import {
  type DependentRow,
  type InsuranceRow,
  type DependentCategory,
  type InsuranceKind,
  computeInsuranceDeduction,
  basicDeduction,
  spouseDeduction,
  dependentDeduction,
  reconcile,
} from "./tax";

/* ------------------------------------------------------------------ *
 * Static employee / 収入 context (read-only, would come from payroll). *
 * ------------------------------------------------------------------ */
const EMPLOYEE = {
  name: "佐藤 美咲",
  employeeNo: "EMP-20471",
  year: 2026,
};
const INCOME = {
  grossSalary: 6_200_000, // 本年の給与収入（総支給）
  incomeAfterEmploymentDeduction: 4_560_000, // 給与所得控除後の金額
  socialInsurance: 912_000, // 社会保険料（給与天引分）
  taxAlreadyWithheld: 178_500, // 既に源泉徴収済みの税額
};

type SubmissionStatus = "draft" | "submitted" | "returned" | "approved";

const STATUS_META: Record<
  SubmissionStatus,
  { label: string; variant: "secondary" | "info" | "warning" | "success"; icon: React.ReactNode }
> = {
  draft: { label: "下書き", variant: "secondary", icon: <IconClipboardCheck className="h-3 w-3" aria-hidden /> },
  submitted: { label: "提出済", variant: "info", icon: <IconCheck className="h-3 w-3" aria-hidden /> },
  returned: { label: "差戻し", variant: "warning", icon: <IconArrowBackUp className="h-3 w-3" aria-hidden /> },
  approved: { label: "確認済", variant: "success", icon: <IconCheck className="h-3 w-3" aria-hidden /> },
};

const RELATIONSHIP_OPTIONS = ["", "子", "父", "母", "祖父", "祖母", "兄弟姉妹", "その他"];
const DEPENDENT_CATEGORY_OPTIONS: Array<{ value: DependentCategory; label: string }> = [
  { value: "general", label: "一般扶養（38万）" },
  { value: "specific", label: "特定扶養（63万）" },
  { value: "elderly", label: "老人扶養（48万）" },
  { value: "cohabiting-elderly", label: "同居老親（58万）" },
];
const INSURANCE_KIND_OPTIONS: Array<{ value: InsuranceKind; label: string }> = [
  { value: "general-life", label: "一般生命" },
  { value: "care-medical", label: "介護医療" },
  { value: "pension", label: "個人年金" },
  { value: "earthquake", label: "地震保険" },
];

let _uid = 0;
const newId = (prefix: string) => `${prefix}-${++_uid}`;

function YearEndDeclarationInner() {
  const [status, setStatus] = React.useState<SubmissionStatus>("draft");
  const readOnly = status === "submitted" || status === "approved";

  // --- 扶養親族 ---
  const [dependents, setDependents] = React.useState<DependentRow[]>([
    {
      id: newId("dep"),
      name: "佐藤 陽翔",
      relationship: "子",
      birthDate: "2005-04-12",
      category: "specific",
      estimatedIncome: 0,
    },
  ]);

  // --- 配偶者 ---
  const [hasSpouse, setHasSpouse] = React.useState(true);
  const [spouseIncome, setSpouseIncome] = React.useState<number | undefined>(380_000);

  // --- 保険料控除 ---
  const [insurances, setInsurances] = React.useState<InsuranceRow[]>([
    { id: newId("ins"), company: "ぐんじょう生命", kind: "general-life", amount: 96_000 },
    { id: newId("ins"), company: "あおい損保", kind: "earthquake", amount: 42_000 },
  ]);

  // --- その他控除 ---
  const [housingLoanCredit, setHousingLoanCredit] = React.useState<number | undefined>(0);
  const [smallEnterprise, setSmallEnterprise] = React.useState<number | undefined>(0);

  // --- 提出/差戻し ---
  const [returnComment, setReturnComment] = React.useState("");
  const [submitAttempted, setSubmitAttempted] = React.useState(false);

  /* ---------------------- derived 計算 ---------------------- */
  const insuranceBreakdown = React.useMemo(() => computeInsuranceDeduction(insurances), [insurances]);

  const spouse = React.useMemo(
    () => spouseDeduction(hasSpouse, spouseIncome ?? 0),
    [hasSpouse, spouseIncome]
  );
  const depDeduction = React.useMemo(() => dependentDeduction(dependents), [dependents]);
  const basic = basicDeduction(INCOME.incomeAfterEmploymentDeduction);

  const result = React.useMemo(
    () =>
      reconcile({
        incomeAfterEmploymentDeduction: INCOME.incomeAfterEmploymentDeduction,
        socialInsurance: INCOME.socialInsurance,
        insuranceDeduction: insuranceBreakdown.total,
        basicDeduction: basic,
        spouseDeduction: spouse.amount,
        dependentDeduction: depDeduction,
        housingLoanCredit: housingLoanCredit ?? 0,
        smallEnterpriseMutualAid: smallEnterprise ?? 0,
        taxAlreadyWithheld: INCOME.taxAlreadyWithheld,
      }),
    [insuranceBreakdown.total, basic, spouse.amount, depDeduction, housingLoanCredit, smallEnterprise]
  );

  /* ---------------------- validation ---------------------- */
  const depError = (row: DependentRow): string | undefined => {
    if (!row.name.trim()) return "氏名を入力してください。";
    if (!row.relationship) return "続柄を選択してください。";
    if (!row.birthDate) return "生年月日を入力してください。";
    if (!row.category) return "区分を選択してください。";
    return undefined;
  };
  const insError = (row: InsuranceRow): string | undefined => {
    if (!row.company.trim()) return "保険会社を入力してください。";
    if (!row.kind) return "種類を選択してください。";
    if (row.amount === undefined || row.amount <= 0) return "支払金額を入力してください。";
    return undefined;
  };

  const dependentErrors = dependents.map(depError);
  const insuranceErrors = insurances.map(insError);
  const hasDependentErrors = dependentErrors.some(Boolean);
  const hasInsuranceErrors = insuranceErrors.some(Boolean);
  const spouseError = hasSpouse && spouseIncome === undefined ? "配偶者の所得見積額を入力してください。" : undefined;
  const isValid = !hasDependentErrors && !hasInsuranceErrors && !spouseError;

  const showErrors = submitAttempted;

  /* ---------------------- 扶養親族 grid columns ---------------------- */
  const depColumns: EditableColumn<DependentRow>[] = [
    {
      id: "name",
      header: "氏名",
      minWidth: "9rem",
      cell: (row, ctx) => (
        <Input
          aria-label={ctx.ariaLabel}
          value={row.name}
          disabled={readOnly}
          aria-invalid={showErrors && !row.name.trim() ? true : undefined}
          onChange={(e) => updateDependent(ctx.rowIndex, { name: e.target.value })}
        />
      ),
    },
    {
      id: "relationship",
      header: "続柄",
      width: "7rem",
      cell: (row, ctx) => (
        <Select
          aria-label={ctx.ariaLabel}
          value={row.relationship}
          disabled={readOnly}
          aria-invalid={showErrors && !row.relationship ? true : undefined}
          onChange={(e) => updateDependent(ctx.rowIndex, { relationship: e.target.value })}
        >
          <option value="">選択</option>
          {RELATIONSHIP_OPTIONS.filter(Boolean).map((r) => (
            <option key={r} value={r}>
              {r}
            </option>
          ))}
        </Select>
      ),
    },
    {
      id: "birthDate",
      header: "生年月日",
      width: "11rem",
      cell: (row, ctx) => (
        <DatePicker
          editable
          locale={ja}
          dateFormat="yyyy/MM/dd"
          placeholder="例) 2005/04/12"
          disabled={readOnly}
          calendarLabel={ctx.ariaLabel}
          startMonth={new Date(1920, 0)}
          endMonth={new Date(EMPLOYEE.year, 11)}
          value={row.birthDate ? new Date(row.birthDate) : undefined}
          onValueChange={(d) => updateDependent(ctx.rowIndex, { birthDate: d ? toIso(d) : "" })}
        />
      ),
    },
    {
      id: "category",
      header: "区分",
      minWidth: "10rem",
      cell: (row, ctx) => (
        <Select
          aria-label={ctx.ariaLabel}
          value={row.category}
          disabled={readOnly}
          aria-invalid={showErrors && !row.category ? true : undefined}
          onChange={(e) =>
            updateDependent(ctx.rowIndex, { category: e.target.value as DependentCategory | "" })
          }
        >
          <option value="">選択</option>
          {DEPENDENT_CATEGORY_OPTIONS.map((o) => (
            <option key={o.value} value={o.value}>
              {o.label}
            </option>
          ))}
        </Select>
      ),
    },
    {
      id: "income",
      header: "所得見積額",
      align: "right",
      width: "9rem",
      cell: (row, ctx) => (
        <CurrencyInput
          aria-label={ctx.ariaLabel}
          value={row.estimatedIncome}
          min={0}
          disabled={readOnly}
          onValueChange={(v) => updateDependent(ctx.rowIndex, { estimatedIncome: v })}
        />
      ),
    },
  ];

  /* ---------------------- 保険料控除 grid columns ---------------------- */
  const insColumns: EditableColumn<InsuranceRow>[] = [
    {
      id: "company",
      header: "保険会社",
      minWidth: "10rem",
      cell: (row, ctx) => (
        <Input
          aria-label={ctx.ariaLabel}
          value={row.company}
          disabled={readOnly}
          aria-invalid={showErrors && !row.company.trim() ? true : undefined}
          onChange={(e) => updateInsurance(ctx.rowIndex, { company: e.target.value })}
        />
      ),
    },
    {
      id: "kind",
      header: "種類",
      minWidth: "9rem",
      cell: (row, ctx) => (
        <Select
          aria-label={ctx.ariaLabel}
          value={row.kind}
          disabled={readOnly}
          aria-invalid={showErrors && !row.kind ? true : undefined}
          onChange={(e) => updateInsurance(ctx.rowIndex, { kind: e.target.value as InsuranceKind | "" })}
        >
          <option value="">選択</option>
          {INSURANCE_KIND_OPTIONS.map((o) => (
            <option key={o.value} value={o.value}>
              {o.label}
            </option>
          ))}
        </Select>
      ),
    },
    {
      id: "amount",
      header: "支払金額",
      align: "right",
      width: "11rem",
      cell: (row, ctx) => (
        <CurrencyInput
          aria-label={ctx.ariaLabel}
          value={row.amount}
          min={0}
          disabled={readOnly}
          aria-invalid={showErrors && (row.amount === undefined || row.amount <= 0) ? true : undefined}
          onValueChange={(v) => updateInsurance(ctx.rowIndex, { amount: v })}
        />
      ),
    },
  ];

  /* ---------------------- mutations ---------------------- */
  function updateDependent(index: number, patch: Partial<DependentRow>) {
    setDependents((rows) => rows.map((r, i) => (i === index ? { ...r, ...patch } : r)));
  }
  function updateInsurance(index: number, patch: Partial<InsuranceRow>) {
    setInsurances((rows) => rows.map((r, i) => (i === index ? { ...r, ...patch } : r)));
  }

  /* ---------------------- approval steps ---------------------- */
  const approvalSteps: ApprovalStep[] = [
    {
      label: "申告者（本人）",
      actor: EMPLOYEE.name,
      state: status === "draft" ? "current" : status === "returned" ? "current" : "approved",
      timestamp: status === "draft" || status === "returned" ? "入力中" : "2026/12/03 提出",
      comment:
        status === "returned" && returnComment
          ? undefined
          : undefined,
    },
    {
      label: "人事確認",
      actor: "人事部 田中",
      state:
        status === "approved"
          ? "approved"
          : status === "submitted"
          ? "current"
          : status === "returned"
          ? "rejected"
          : "pending",
      timestamp:
        status === "approved" ? "2026/12/05 確認済" : status === "submitted" ? "確認待ち" : undefined,
      comment: status === "returned" && returnComment ? returnComment : undefined,
    },
  ];

  /* ---------------------- actions ---------------------- */
  function handleSubmit() {
    setSubmitAttempted(true);
    if (!isValid) {
      // move focus / announce handled by FormMessage role=alert + grid getRowError
      return;
    }
    setStatus("submitted");
  }
  function handleReturn() {
    setStatus("returned");
  }
  function handleApprove() {
    setStatus("approved");
  }
  function handleReopen() {
    setStatus("draft");
    setSubmitAttempted(false);
  }

  /* ---------------------- 還付/追徴 presentation ---------------------- */
  const settlementAbs = Math.abs(result.settlement);
  const isRefund = result.settlementType === "refund";
  const isCollect = result.settlementType === "collect";
  const settlementVariant = isRefund ? "success" : isCollect ? "destructive" : "info";
  const settlementHeading = isRefund
    ? "還付（戻ってくる金額）"
    : isCollect
    ? "追徴（不足し追加で納める金額）"
    : "過不足なし";
  const settlementIcon = isRefund ? (
    <IconCoin className="h-4 w-4" aria-hidden />
  ) : isCollect ? (
    <IconAlertTriangle className="h-4 w-4" aria-hidden />
  ) : (
    <IconInfoCircle className="h-4 w-4" aria-hidden />
  );

  const allZero =
    dependents.length === 0 &&
    insurances.length === 0 &&
    !hasSpouse &&
    !(housingLoanCredit ?? 0) &&
    !(smallEnterprise ?? 0);

  const statusMeta = STATUS_META[status];

  return (
    <Container size="xl" as="main" className="py-8">
      <VStack gap={8}>
        {/* ===== 対象ヘッダ ===== */}
        <VStack gap={3} aria-labelledby="page-heading">
          <Cluster justify="between" align="start" gap={3}>
            <VStack gap={1}>
              <p className="text-sm text-muted-foreground">年末調整 申告</p>
              <h1 id="page-heading" className="text-2xl font-bold tracking-tight">
                {EMPLOYEE.year}年分 給与所得者の申告
              </h1>
              <HStack gap={3} wrap className="text-sm text-muted-foreground">
                <span>
                  従業員: <span className="font-medium text-foreground">{EMPLOYEE.name}</span>
                </span>
                <span aria-hidden>·</span>
                <span>社員番号: {EMPLOYEE.employeeNo}</span>
              </HStack>
            </VStack>
            <VStack gap={1} align="end">
              <span className="text-xs text-muted-foreground" id="status-label">
                提出ステータス
              </span>
              <Badge variant={statusMeta.variant} aria-labelledby="status-label" className="gap-1">
                {statusMeta.icon}
                {statusMeta.label}
              </Badge>
            </VStack>
          </Cluster>

          {status === "returned" ? (
            <Alert variant="warning" aria-live="polite">
              <IconArrowBackUp className="h-4 w-4" aria-hidden />
              <AlertTitle as="h2">人事から差戻されています</AlertTitle>
              <AlertDescription>
                {returnComment || "内容をご確認のうえ、修正して再提出してください。"}
              </AlertDescription>
            </Alert>
          ) : null}
          {readOnly ? (
            <Alert variant="info" aria-live="polite">
              <IconCheck className="h-4 w-4" aria-hidden />
              <AlertTitle as="h2">
                {status === "approved" ? "人事確認まで完了しています" : "提出済みです"}
              </AlertTitle>
              <AlertDescription>
                この申告は読み取り専用です。修正するには差戻し、または再編集してください。
              </AlertDescription>
            </Alert>
          ) : null}
        </VStack>

        <Grid cols={1} gap={6} className="lg:grid-cols-3">
          {/* ================= 左カラム：申告フォーム ================= */}
          <div className="lg:col-span-2">
            <VStack gap={6}>
              {/* ---- 基本・収入 ---- */}
              <Card>
                <CardHeader>
                  <CardTitle as="h2">基本・収入</CardTitle>
                  <CardDescription>
                    給与システムから連携された金額です（読み取り専用）。
                  </CardDescription>
                </CardHeader>
                <CardContent>
                  <Grid cols={1} gap={4} className="sm:grid-cols-3">
                    <ReadonlyAmount label="本年の給与収入（総支給）" value={INCOME.grossSalary} />
                    <ReadonlyAmount
                      label="給与所得控除後の金額"
                      value={INCOME.incomeAfterEmploymentDeduction}
                    />
                    <ReadonlyAmount label="社会保険料（給与天引分）" value={INCOME.socialInsurance} />
                  </Grid>
                </CardContent>
              </Card>

              {/* ---- 扶養親族の申告 ---- */}
              <Card>
                <CardHeader>
                  <CardTitle as="h2">扶養親族の申告</CardTitle>
                  <CardDescription>
                    扶養控除の対象となる親族を入力します。所得見積額が48万円を超える方は控除対象外です。
                  </CardDescription>
                </CardHeader>
                <CardContent>
                  <EditableDataTable<DependentRow>
                    columns={depColumns}
                    rows={dependents}
                    getRowId={(r) => r.id}
                    rowLabel={(i) => `扶養親族${i + 1}`}
                    getRowError={showErrors ? (r) => depError(r) : undefined}
                    onAddRow={
                      readOnly
                        ? undefined
                        : () =>
                            setDependents((rows) => [
                              ...rows,
                              {
                                id: newId("dep"),
                                name: "",
                                relationship: "",
                                birthDate: "",
                                category: "",
                                estimatedIncome: 0,
                              },
                            ])
                    }
                    onRemoveRow={
                      readOnly
                        ? undefined
                        : (i) => setDependents((rows) => rows.filter((_, idx) => idx !== i))
                    }
                    labels={{
                      addRow: "扶養親族を追加",
                      removeRow: (i) => `扶養親族${i + 1}を削除`,
                      empty: "扶養親族の登録はありません。",
                    }}
                    renderFooterCell={(col) =>
                      col.id === "income" ? (
                        <span className="tabular-nums">
                          扶養控除 計 {formatCurrency(depDeduction)}
                        </span>
                      ) : col.id === "name" ? (
                        <span className="text-muted-foreground">
                          対象 {dependents.filter((d) => d.category && (d.estimatedIncome ?? 0) <= 480000).length} 名
                        </span>
                      ) : null
                    }
                  />

                  <Separator className="my-5" />

                  {/* 配偶者 */}
                  <VStack gap={3}>
                    <Switch
                      checked={hasSpouse}
                      disabled={readOnly}
                      onCheckedChange={setHasSpouse}
                      label="配偶者がいる"
                      description="配偶者控除・配偶者特別控除の判定に使用します。"
                    />
                    {hasSpouse ? (
                      <div
                        className="rounded-lg border bg-muted/30 p-4"
                        role="region"
                        aria-label="配偶者控除の判定"
                      >
                        <Form>
                          <FormField error={showErrors ? spouseError : undefined}>
                            <FormLabel>配偶者の所得見積額（合計所得）</FormLabel>
                            <FormControl>
                              <CurrencyInput
                                value={spouseIncome}
                                min={0}
                                disabled={readOnly}
                                onValueChange={setSpouseIncome}
                              />
                            </FormControl>
                            <FormDescription>
                              48万円以下なら配偶者控除、48万円超〜133万円なら配偶者特別控除の対象です。
                            </FormDescription>
                            <FormMessage />
                          </FormField>
                        </Form>
                        <HStack gap={2} className="mt-3" wrap aria-live="polite">
                          <span className="text-sm text-muted-foreground">判定:</span>
                          <Badge variant={spouse.amount > 0 ? "success" : "secondary"}>
                            {spouse.kind}
                          </Badge>
                          <span className="text-sm font-medium tabular-nums">
                            控除額 {formatCurrency(spouse.amount)}
                          </span>
                        </HStack>
                      </div>
                    ) : null}
                  </VStack>
                </CardContent>
              </Card>

              {/* ---- 保険料控除の申告 ---- */}
              <Card>
                <CardHeader>
                  <CardTitle as="h2">保険料控除の申告</CardTitle>
                  <CardDescription>
                    生命保険料控除は区分ごとに上限4万円・3区分合計で上限12万円、地震保険料控除は上限5万円が適用されます。
                  </CardDescription>
                </CardHeader>
                <CardContent>
                  <EditableDataTable<InsuranceRow>
                    columns={insColumns}
                    rows={insurances}
                    getRowId={(r) => r.id}
                    rowLabel={(i) => `保険${i + 1}`}
                    getRowError={showErrors ? (r) => insError(r) : undefined}
                    onAddRow={
                      readOnly
                        ? undefined
                        : () =>
                            setInsurances((rows) => [
                              ...rows,
                              { id: newId("ins"), company: "", kind: "", amount: undefined },
                            ])
                    }
                    onRemoveRow={
                      readOnly
                        ? undefined
                        : (i) => setInsurances((rows) => rows.filter((_, idx) => idx !== i))
                    }
                    labels={{
                      addRow: "保険料を追加",
                      removeRow: (i) => `保険${i + 1}を削除`,
                      empty: "保険料控除の登録はありません。",
                    }}
                    renderFooterCell={(col) =>
                      col.id === "amount" ? (
                        <span className="tabular-nums">
                          控除額 計 {formatCurrency(insuranceBreakdown.total)}
                        </span>
                      ) : null
                    }
                  />

                  {/* per-category 控除額 assist */}
                  <dl className="mt-4 grid grid-cols-2 gap-x-4 gap-y-2 rounded-lg border bg-muted/30 p-4 text-sm sm:grid-cols-4">
                    <DeductionStat label="一般生命" value={insuranceBreakdown.generalLife} />
                    <DeductionStat label="介護医療" value={insuranceBreakdown.careMedical} />
                    <DeductionStat label="個人年金" value={insuranceBreakdown.pension} />
                    <DeductionStat label="地震保険" value={insuranceBreakdown.earthquake} />
                    <div className="col-span-2 sm:col-span-4">
                      <Separator className="my-1" />
                    </div>
                    <DeductionStat label="生命保険料控除 計（上限12万）" value={insuranceBreakdown.lifeTotal} />
                    <div className="col-span-1 sm:col-span-3 flex items-end justify-end">
                      <span className="text-sm font-medium tabular-nums">
                        保険料控除 総額 {formatCurrency(insuranceBreakdown.total)}
                      </span>
                    </div>
                  </dl>
                </CardContent>
              </Card>

              {/* ---- 基礎控除 / その他控除 ---- */}
              <Card>
                <CardHeader>
                  <CardTitle as="h2">基礎控除・その他控除</CardTitle>
                  <CardDescription>住宅借入金等特別控除と小規模企業共済等掛金を入力します。</CardDescription>
                </CardHeader>
                <CardContent>
                  <Grid cols={1} gap={4} className="sm:grid-cols-3">
                    <div>
                      <p className="text-xs font-medium text-muted-foreground">基礎控除（自動）</p>
                      <p className="mt-1 text-lg font-semibold tabular-nums">{formatCurrency(basic)}</p>
                      <p className="text-xs text-muted-foreground">本人の所得に応じて自動判定</p>
                    </div>
                    <Form>
                      <FormField>
                        <FormLabel>住宅借入金等特別控除</FormLabel>
                        <FormControl>
                          <CurrencyInput
                            value={housingLoanCredit}
                            min={0}
                            disabled={readOnly}
                            onValueChange={setHousingLoanCredit}
                          />
                        </FormControl>
                        <FormDescription>税額からの控除（残高証明の額）</FormDescription>
                      </FormField>
                    </Form>
                    <Form>
                      <FormField>
                        <FormLabel>小規模企業共済等掛金</FormLabel>
                        <FormControl>
                          <CurrencyInput
                            value={smallEnterprise}
                            min={0}
                            disabled={readOnly}
                            onValueChange={setSmallEnterprise}
                          />
                        </FormControl>
                        <FormDescription>iDeCo 等の掛金（所得控除）</FormDescription>
                      </FormField>
                    </Form>
                  </Grid>
                </CardContent>
              </Card>
            </VStack>
          </div>

          {/* ================= 右カラム：精算 & フロー ================= */}
          <div className="lg:col-span-1">
            <VStack gap={6} className="lg:sticky lg:top-6">
              {/* ---- 精算結果 ---- */}
              <Card>
                <CardHeader>
                  <CardTitle as="h2">精算結果</CardTitle>
                  <CardDescription>申告内容に応じて自動で再計算されます。</CardDescription>
                </CardHeader>
                <CardContent>
                  <VStack gap={4}>
                    {allZero ? (
                      <Alert variant="info">
                        <IconInfoCircle className="h-4 w-4" aria-hidden />
                        <AlertTitle as="h3">控除の入力がありません</AlertTitle>
                        <AlertDescription>
                          扶養・保険料などを入力すると、過不足額が計算されます。
                        </AlertDescription>
                      </Alert>
                    ) : null}

                    <Grid cols={2} gap={3}>
                      <Statistic label="課税対象額" value={formatCurrency(result.taxableIncome)} />
                      <Statistic label="算出税額" value={formatCurrency(result.calculatedTax)} />
                      <Statistic label="年調年税額" value={formatCurrency(result.finalAnnualTax)} />
                      <Statistic
                        label="既源泉徴収税額"
                        value={formatCurrency(INCOME.taxAlreadyWithheld)}
                      />
                    </Grid>

                    <dl className="rounded-lg border bg-muted/30 p-3 text-sm">
                      <Row label="所得控除 合計" value={formatCurrency(result.totalIncomeDeductions)} />
                      <Row label="うち 基礎控除" value={formatCurrency(basic)} muted />
                      <Row label="うち 配偶者(特別)控除" value={formatCurrency(spouse.amount)} muted />
                      <Row label="うち 扶養控除" value={formatCurrency(depDeduction)} muted />
                      <Row label="うち 保険料控除" value={formatCurrency(insuranceBreakdown.total)} muted />
                      <Row
                        label="うち 小規模企業共済等"
                        value={formatCurrency(smallEnterprise ?? 0)}
                        muted
                      />
                    </dl>

                    {/* headline 過不足額 */}
                    <Alert variant={settlementVariant} aria-live="polite">
                      {settlementIcon}
                      <AlertTitle as="h3">{settlementHeading}</AlertTitle>
                      <AlertDescription>
                        <span className="block text-2xl font-bold tabular-nums text-foreground">
                          {result.settlementType === "zero"
                            ? formatCurrency(0)
                            : formatCurrency(settlementAbs)}
                        </span>
                        <span className="text-xs">
                          年調年税額 {formatCurrency(result.finalAnnualTax)} − 既源泉徴収{" "}
                          {formatCurrency(INCOME.taxAlreadyWithheld)} ={" "}
                          {formatCurrency(result.settlement, { signed: true })}
                        </span>
                      </AlertDescription>
                    </Alert>
                  </VStack>
                </CardContent>
              </Card>

              {/* ---- 提出フロー ---- */}
              <Card>
                <CardHeader>
                  <CardTitle as="h2">提出フロー</CardTitle>
                  <CardDescription>申告者 → 人事確認</CardDescription>
                </CardHeader>
                <CardContent>
                  <VStack gap={5}>
                    <ApprovalSteps
                      steps={approvalSteps}
                      stateLabels={{
                        pending: "未着手",
                        current: "対応中",
                        approved: "完了",
                        rejected: "差戻し",
                        skipped: "スキップ",
                      }}
                    />

                    {/* validation summary on submit */}
                    {showErrors && !isValid && !readOnly ? (
                      <Alert variant="destructive" aria-live="assertive">
                        <IconAlertTriangle className="h-4 w-4" aria-hidden />
                        <AlertTitle as="h3">入力内容に不足があります</AlertTitle>
                        <AlertDescription>
                          赤くハイライトされた行・項目を修正してから提出してください。
                        </AlertDescription>
                      </Alert>
                    ) : null}

                    {/* actions */}
                    {!readOnly ? (
                      <Button type="button" onClick={handleSubmit} className="w-full">
                        <IconCheck className="h-4 w-4" aria-hidden />
                        {status === "returned" ? "修正して再提出" : "提出する"}
                      </Button>
                    ) : null}

                    {/* 人事側アクション（提出済のときのみ） */}
                    {status === "submitted" ? (
                      <VStack gap={3} className="rounded-lg border p-3">
                        <p className="text-sm font-medium">人事確認アクション</p>
                        <Form>
                          <FormField>
                            <FormLabel>差戻しコメント</FormLabel>
                            <FormControl>
                              <Textarea
                                value={returnComment}
                                onChange={(e) => setReturnComment(e.target.value)}
                                placeholder="差戻す場合は理由を記載してください。"
                                rows={2}
                              />
                            </FormControl>
                          </FormField>
                        </Form>
                        <HStack gap={2}>
                          <Button type="button" variant="success" onClick={handleApprove} className="flex-1">
                            <IconCheck className="h-4 w-4" aria-hidden />
                            確認・承認
                          </Button>
                          <Button
                            type="button"
                            variant="outline"
                            onClick={handleReturn}
                            className="flex-1"
                          >
                            <IconArrowBackUp className="h-4 w-4" aria-hidden />
                            差戻し
                          </Button>
                        </HStack>
                      </VStack>
                    ) : null}

                    {readOnly ? (
                      <Button type="button" variant="outline" onClick={handleReopen} className="w-full">
                        再編集する
                      </Button>
                    ) : null}
                  </VStack>
                </CardContent>
              </Card>
            </VStack>
          </div>
        </Grid>
      </VStack>
    </Container>
  );
}

/* ---------------------- small helpers ---------------------- */
function toIso(d: Date): string {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, "0");
  const day = String(d.getDate()).padStart(2, "0");
  return `${y}-${m}-${day}`;
}

function ReadonlyAmount({ label, value }: { label: string; value: number }) {
  return (
    <div>
      <p className="text-xs font-medium text-muted-foreground">{label}</p>
      <p className="mt-1 text-lg font-semibold tabular-nums">{formatCurrency(value)}</p>
    </div>
  );
}

function DeductionStat({ label, value }: { label: string; value: number }) {
  return (
    <div className="flex flex-col">
      <dt className="text-xs text-muted-foreground">{label}</dt>
      <dd className="font-medium tabular-nums">{formatCurrency(value)}</dd>
    </div>
  );
}

function Row({ label, value, muted }: { label: string; value: string; muted?: boolean }) {
  return (
    <div className="flex items-center justify-between gap-2 py-0.5">
      <dt className={muted ? "text-xs text-muted-foreground" : "text-sm"}>{label}</dt>
      <dd className={muted ? "text-xs tabular-nums text-muted-foreground" : "text-sm font-medium tabular-nums"}>
        {value}
      </dd>
    </div>
  );
}

export default function YearEndDeclaration() {
  return (
    <ThemeProvider defaultTheme="system">
      <YearEndDeclarationInner />
    </ThemeProvider>
  );
}
